// Aggregate health check results from all services
const items = $input.all();

function getStatus(item) {
  if (!item || !item.json) return 'unknown';
  const json = item.json;
  // Check for error indicators
  if (json.error || json.code === 'ECONNREFUSED' || json.code === 'ETIMEDOUT') return 'unhealthy';
  if (json.statusCode && json.statusCode >= 400) return 'unhealthy';
  return 'healthy';
}

// Get results from previous nodes
const openclawResult = $('OpenClaw Health').first();
const n8nResult = $('n8n Health').first();
const postgresResult = $('Postgres Health').first();

const services = {
  openclaw: {
    status: getStatus(openclawResult),
    url: 'http://openclaw:8080/healthz',
    response_code: openclawResult?.json?.statusCode || null
  },
  n8n: {
    status: getStatus(n8nResult),
    url: 'http://localhost:5678/healthz',
    response_code: n8nResult?.json?.statusCode || null
  },
  postgres: {
    status: getStatus(postgresResult),
    url: 'http://postgres:5432/',
    response_code: postgresResult?.json?.statusCode || null
  }
};

const unhealthyServices = Object.entries(services)
  .filter(([_, s]) => s.status !== 'healthy')
  .map(([name, _]) => name);

const allHealthy = unhealthyServices.length === 0;

return [{
  json: {
    all_healthy: allHealthy,
    checked_at: new Date().toISOString(),
    services: services,
    unhealthy_services: unhealthyServices,
    summary: allHealthy
      ? 'All services operational'
      : `ALERT: ${unhealthyServices.join(', ')} unhealthy`
  }
}];
